'use server'

import { cookies } from 'next/headers'
import { refresh } from 'next/cache'

const NOTIFICATION_PREFERENCE_COOKIE = 'notification-preference'

/**
 * Toggle the current user's notification preference and refresh the page that
 * displays it. The cookie stands in for the user's persisted preference in
 * this small example; a database update can be substituted here directly.
 */
export async function toggleNotificationPreference() {
  const cookieStore = await cookies()
  const currentlyEnabled = cookieStore.get(NOTIFICATION_PREFERENCE_COOKIE)?.value !== 'off'
  const enabled = !currentlyEnabled

  cookieStore.set(NOTIFICATION_PREFERENCE_COOKIE, enabled ? 'on' : 'off', {
    httpOnly: true,
    sameSite: 'lax',
    path: '/',
  })

  // Re-render the current route with the value that was just saved. This does
  // not navigate the user to another page.
  refresh()
}

